<script setup lang="ts">import { onMounted, ref } from 'vue'; import { createCategory, listCategories } from '../api/catalog'; import type { CategoryNode } from '../catalog/catalogModels'; import StPageHeader from '../components/StPageHeader.vue'; import StEmptyState from '../components/StEmptyState.vue'; import CategoryTree from '../components/catalog/CategoryTree.vue'; import CategoryEditor from '../components/catalog/CategoryEditor.vue'; const nodes=ref<CategoryNode[]>([]),selected=ref<CategoryNode>(),editing=ref(false),error=ref(''); onMounted(load); async function load(){nodes.value=await listCategories()} function addChild(){selected.value=nodes.value[0];editing.value=true} async function save(data:Parameters<typeof createCategory>[0]){try{const node=await createCategory(data);nodes.value.push(node);editing.value=false}catch(e){error.value=(e as {detail?:string;code?:string}).detail??(e as {code?:string}).code??'保存失败'}}</script>
<template><section><StPageHeader title="分类管理" description="维护分类树和属性模式"><template #actions><button @click="addChild">添加子分类</button></template></StPageHeader><p v-if="error" role="alert">{{ error }}</p><StEmptyState v-if="!nodes.length" title="还没有分类"/><div v-else class="admin-grid"><CategoryTree :nodes="nodes" :selected-id="selected?.id" @select="selected=$event"/><CategoryEditor v-if="editing" :parent="selected" @save="save"/><article v-else-if="selected"><h2>{{ selected.name }}</h2><p>属性字段：{{ selected.attributeSchema.length }}</p></article></div></section></template>
<style scoped>.admin-grid{display:grid;grid-template-columns:minmax(220px,1fr) minmax(300px,2fr);gap:var(--st-space-6)}@media(max-width:720px){.admin-grid{grid-template-columns:1fr}}</style>
